(window.webpackJsonp=window.webpackJsonp||[]).push([[332],{959:function(n,t){n.exports="\x3c!-- \ntitle: 23-JS函数\nsort: \n--\x3e \n# JS函数\n\n## 传参\n\n> `arguments`是包含所有传入参数的数组。\n\n```js\n// 使用多个变量\nfunction add() {\n    var sum = 0;\n    for (var i = 0, j = arguments.length; i < j; i++) {\n        sum += arguments[i];\n    }\n    return sum;\n}\n\nadd(2, 3, 4, 5); // 14\n\n// 或使用剩余参数操作符\nfunction avg(...args) {\n  var sum = 0;\n  for (let value of args) {\n    sum += value;\n  }\n  return sum / args.length;\n}\n\navg(2, 3, 4, 5); // 3.5\n```\n\n## 内部函数\n\n```js\nfunction parentFunc() {\n  var a = 1;\n\n  function nestedFunc() {\n    var b = 4; // parentFunc 无法访问 b\n    return a + b;\n  }\n  return nestedFunc(); // 5\n}\n```\n\n## 函数的属性和方法\n\n```js\nfunc.name\nfunc.length\t\t// 参数个数\nfunc.toString()\t// 函数源码\n```\n"}}]);